import json
import re

import nltk
import numpy as np
import tritonclient.http as httpclient
from nltk.tokenize import word_tokenize

try:
    nltk.data.find("tokenizers/punkt")
except LookupError:
    nltk.download("punkt")
    nltk.download("punkt_tab")


def russian_tokenizer(text):
    """
    russian_tokenizer works like basic_english tokenizer
    """
    text = text.lower()
    tokens = word_tokenize(text, language="russian")

    result = []
    for token in tokens:
        if re.match(r"^\w+$", token):
            result.append(token)
        else:
            parts = re.findall(r"\w+|[^\w\s]", token)
            result.extend([p for p in parts if p])
    return result


class TextClassifierClient:
    def __init__(
        self,
        vocab_path,
        max_pad_len,
        model_name="cbrf_rate_classifier",
        url="localhost:9000",
    ):
        self.client = httpclient.InferenceServerClient(url=url)
        self.model_name = model_name
        self.max_pad_len = max_pad_len

        with open(vocab_path, "r") as f:
            self.vocab_dict = json.load(f)

        if "<unk>" not in self.vocab_dict:
            max_index = max(self.vocab_dict.values()) if self.vocab_dict else 0
            self.vocab_dict["<unk>"] = max_index + 1

        self.unk_index = self.vocab_dict["<unk>"]
        print(f"Загружен словарь из {len(self.vocab_dict)} токенов")
        print(f"UNK индекс: {self.unk_index}")

    def preprocessing(self, text: str) -> str:
        """
        Preprocessing sentence - ТОЧНО КАК ПРИ ОБУЧЕНИИ!
        """
        text = text.lower()
        text = re.sub(r"[^\w\s]", "", text)
        tokens = russian_tokenizer(text)
        return " ".join(tokens)

    def tk(self, text: str):
        """
        Tokenization - ТОЧНО КАК ПРИ ОБУЧЕНИИ!
        """
        return russian_tokenizer(text)

    def pad_num_sentences(self, sequence, max_len, pad_value=0):
        """
        Pads tokenized sentences - аналогично обучению
        """
        if len(sequence) >= max_len:
            return sequence[:max_len]
        else:
            return sequence + [pad_value] * (max_len - len(sequence))

    def preprocess_text(self, text: str) -> np.ndarray:
        """
        Preprocessing text
        """
        preprocessed = self.preprocessing(text)
        print(f"[DEBUG] После препроцессинга: '{preprocessed[:100]}...'")

        tokens = self.tk(preprocessed)
        print(f"[DEBUG] Токенов: {len(tokens)}")
        print(f"[DEBUG] Первые 10 токенов: {tokens[:10]}")

        sequence = []
        unk_count = 0
        for token in tokens:
            if token in self.vocab_dict:
                sequence.append(self.vocab_dict[token])
            else:
                sequence.append(self.unk_index)
                unk_count += 1

        print(
            f"[DEBUG] UNK токенов: {unk_count}/{len(tokens)} ({unk_count/len(tokens)*100:.1f}%)"
        )
        print(f"[DEBUG] Первые 10 индексов: {sequence[:10]}")

        padded_sequence = self.pad_num_sentences(sequence, self.max_pad_len)
        print(
            f"[DEBUG] После паддинга (длина {len(padded_sequence)}): {padded_sequence[:10]}..."
        )

        return np.array([padded_sequence], dtype=np.int64)

    def classify_text(self, text: str, debug: bool = False) -> dict:
        """
        Classify text and return results
        """
        if debug:
            print("КЛАССИФИКАЦИЯ ТЕКСТА:")
            print(f"Длина текста: {len(text)} символов")

        input_array = self.preprocess_text(text)

        if debug:
            print(f"[DEBUG] Форма входных данных: {input_array.shape}")
            print(f"[DEBUG] Тип данных: {input_array.dtype}")

        inputs = [
            httpclient.InferInput("PREPROCESSED_TEXT", input_array.shape, "INT64")
        ]
        inputs[0].set_data_from_numpy(input_array)

        outputs = [httpclient.InferRequestedOutput("LOGITS")]

        try:
            response = self.client.infer(
                model_name=self.model_name, inputs=inputs, outputs=outputs
            )

            logits = response.as_numpy("LOGITS")

            if debug:
                print(f"[DEBUG] Форма логитов: {logits.shape}")
                print(f"[DEBUG] Логиты: {logits}")

            exp_logits = np.exp(logits - np.max(logits, axis=-1, keepdims=True))
            probabilities = exp_logits / exp_logits.sum(axis=-1, keepdims=True)

            predicted_class = int(np.argmax(probabilities))

            return {
                "text": text[:200] + "..." if len(text) > 200 else text,
                "predicted_class": predicted_class,
                "probabilities": probabilities[0].tolist(),
                "logits": logits[0].tolist(),
                "input_shape": input_array.shape,
            }

        except Exception as e:
            print(f"Ошибка при запросе к Triton: {e}")
            return {"error": str(e)}


